class Solution:

    def __init__(self):
        self.cursor = -1
        self.main_stack = []
        self.min_stack = []

    def push(self, node):
        if self.cursor == -1:
            self.main_stack.append(node)
            self.min_stack.append(node)
        else:
            if self.min_stack[self.cursor] <= node:
                self.min_stack.append(self.min_stack[self.cursor])
            else:
                self.min_stack.append(node)
            self.main_stack.append(node)
        self.cursor += 1

    def pop(self):
        if self.cursor == -1:
            return None
        else:
            del self.min_stack[self.cursor]
            result = self.main_stack[self.cursor]
            del self.main_stack[self.cursor]
            self.cursor -= 1
            return result

    def top(self):
        if self.cursor == -1:
            return None
        else:
            return self.main_stack[self.cursor]

    def min(self):
        if self.cursor == -1:
            return None
        else:
            return self.min_stack[self.cursor]
